const item = $input.first().json;
if (!item.circuit_key || !item.status || !item.previous_status) {
  return [{ json: { hasTransition: false, transitionQuery: 'SELECT 1' } }];
}
const traceId = 'heartbeat-recovery-' + Date.now();
const from = item.previous_status;
const to = item.status;
const transitionQuery = `INSERT INTO supervisor_events (trace_id, event_type, workflow_name, execution_id, severity, status, payload) VALUES ('${traceId}', 'circuit_transition', 'Heartbeat Monitor', 'heartbeat', 'info', '${to}', '{"from": "${from}", "to": "${to}", "reason": "heartbeat_recovery_probe", "cooldown_minutes": ${from === 'open' ? 5 : 10}}')`;
return [{ json: { hasTransition: true, transitionQuery, from, to } }];

const crypto = require('crypto');
const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

const isDbError = item.error && typeof item.error === 'object' && item.error.message;
const cs = isDbError ? 'unknown' : (item.circuit_status || 'unknown');
const ec = isDbError ? 0 : (parseInt(item.error_count) || 0);
const errHour = isDbError ? 0 : (parseInt(item.errors_last_hour) || 0);
const err24h = isDbError ? 0 : (parseInt(item.errors_last_24h) || 0);
const circuitIcon = cs === 'closed' ? '🟢' : cs === 'half_open' ? '🟡' : cs === 'open' ? '🔴' : '⚪';
const trend = errHour >= 3 ? '🔴 spike' : err24h >= 10 ? '🟡 elevated' : '🟢 stable';

let emergencyNote = '';
const cachedCount = (staticData.eventFailures && staticData.eventFailures.length) || 0;
const droppedCount = staticData.droppedCacheCount || 0;
if (cachedCount > 0) {
  emergencyNote = `\n\n🚨 Emergency Cache: ${cachedCount} failed event(s) detected since last heartbeat`;
  if (droppedCount > 0) emergencyNote += ` (${droppedCount} older events dropped due to cache overflow)`;
}

let dmsNote = '';
if (staticData.lastDeadMansSwitchFailure) dmsNote = `\n\n⚠️ Last DMS Ping Failure: ${staticData.lastDeadMansSwitchFailure}`;
let orphanNote = '';
if (staticData.orphanUncertainty) orphanNote = `\n\n⚠️ Orphan Detection Uncertain: ${staticData.orphanUncertainty.reason} (at ${staticData.orphanUncertainty.timestamp})`;

const text = `💓 HEARTBEAT — Supervisor V1 Lean\n\nCircuit: ${circuitIcon} ${cs} (${ec} errors)\nErrors (1h): ${errHour}\nErrors (24h): ${err24h}\nTrend: ${trend}${isDbError ? '\n\n🔴 DATABASE UNREACHABLE' : ''}${emergencyNote}${dmsNote}${orphanNote}\n\nTimestamp: ${new Date().toISOString()}`;

const hashInput = `${cs}:${ec}:${errHour}:${err24h}:${isDbError}:${!!emergencyNote}:${!!dmsNote}:${!!orphanNote}`;
const messageHash = crypto.createHash('md5').update(hashInput).digest('hex');
const lastHash = staticData.lastHeartbeatHash || '';
const isDuplicate = messageHash === lastHash;
staticData.lastHeartbeatHash = messageHash;
const isDegraded = isDbError || cs === 'open' || cs === 'half_open' || !!emergencyNote || !!dmsNote || !!orphanNote;

return [{ json: { text, messageHash, isDuplicate, isDegraded, dbError: isDbError, circuit_status: cs, error_count: ec, errors_last_hour: errHour, errors_last_24h: err24h } }];

const item = $input.first().json || {};
const isError = (typeof item.error === 'object' && item.error !== null && item.error.message);
if (isError) {
  const staticData = $getWorkflowStaticData('global');
  staticData.lastDeadMansSwitchFailure = item.error.message;
}
return [{ json: { ...item, dmsFailure: isError, dmsErrorMessage: isError ? item.error.message : '' } }];

