const staticData = $getWorkflowStaticData('global');
staticData.eventFailures = [];
staticData.droppedCacheCount = 0;
delete staticData.lastDeadMansSwitchFailure;
delete staticData.orphanUncertainty;
return [{ json: { cacheCleared: true } }];

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

if (item.error || (typeof item === 'object' && item.error)) {
  return [{ json: { apiError: true, hasOrphans: false, orphans: [], orphanQuery: 'SELECT 1', errorMessage: item.error?.message || 'API unreachable' } }];
}

const data = item.data || item;
const arr = Array.isArray(data) ? data : (data.data || []);

if (arr.length === 0) {
  const healthData = (() => { try { return $('Evaluate System Health').first().json; } catch(e) { return {}; } })();
  const isActiveSystem = healthData.circuit_status === 'open' || healthData.circuit_status === 'half_open' || healthData.dbError;
  if (isActiveSystem) {
    staticData.orphanUncertainty = { timestamp: new Date().toISOString(), reason: 'API returned 0 running executions during active system (circuit: ' + (healthData.circuit_status || 'unknown') + ')' };
    return [{ json: { apiError: false, hasOrphans: false, orphans: [], orphanQuery: 'SELECT 1', uncertainResult: true } }];
  }
  return [{ json: { apiError: false, hasOrphans: false, orphans: [], orphanQuery: 'SELECT 1' } }];
}

const now = Date.now();
const threshold = 30 * 60 * 1000;
const MONITORING_WORKFLOW_IDS = [
  $env.SUPERVISOR_WORKFLOW_ID || '',
  $env.HEARTBEAT_WORKFLOW_ID || '',
  $env.RETENTION_WORKFLOW_ID || ''
].filter(Boolean);

const orphans = arr.filter(exec => {
  const startedAt = new Date(exec.startedAt || exec.createdAt).getTime();
  return (now - startedAt) > threshold && !MONITORING_WORKFLOW_IDS.includes(String(exec.workflowId));
}).map(exec => ({
  executionId: exec.id,
  workflowId: exec.workflowId,
  workflowName: exec.workflowName || 'unknown',
  startedAt: exec.startedAt || exec.createdAt,
  runningMinutes: Math.round((now - new Date(exec.startedAt || exec.createdAt).getTime()) / 60000)
}));

const esc = (s) => String(s ?? '').replace(/'/g, "''");
let orphanQuery = 'SELECT 1';
if (orphans.length > 0) {
  const values = orphans.map(o => {
    const payload = JSON.stringify({ orphanCount: orphans.length, runningMinutes: o.runningMinutes, workflowId: o.workflowId }).replace(/'/g, "''");
    return `('orphan-${o.executionId}-' || EXTRACT(EPOCH FROM NOW())::INTEGER, 'orphan_detected', '${esc(o.workflowName)}', '${o.executionId}', 'warning', 'detected', '${payload}')`;
  }).join(',\n  ');
  orphanQuery = `INSERT INTO supervisor_events (trace_id, event_type, workflow_name, execution_id, severity, status, payload)\nVALUES\n  ${values}\nON CONFLICT DO NOTHING`;
}

return [{ json: { apiError: false, hasOrphans: orphans.length > 0, orphans, orphanCount: orphans.length, orphanQuery } }];

